import numpy as np

# Common backbone idea: Balancing cost metrics such as distance, time windows, and penalties to select the next node.
# {New algorithm, Heuristic Adaptive Routing (HAR), adaptively applies heuristics to dynamically determine node sequence based on real-time logistical constraints and priorities.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    best_priority = -float('inf')
    best_node = None

    for i, customer_pos in enumerate(unvisited_customers):
        distance = calculate_distance(cur_truck_pos, customer_pos)
        travel_time = distance / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[i]

        if arrival_time > end_window:
            priority = -float('inf')  # Missing time window is unacceptable
        else:
            time_window_priority = 1 / (1 + max(start_window - arrival_time, 0))  # Higher for earlier windows
            proximity_priority = 1 / (1 + distance)  # Closer nodes have higher priority
            distribution_priority = len([1 for other_truck_pos in all_truck_pos if calculate_distance(customer_pos, other_truck_pos) < distance / 2])

            priority = time_window_priority + proximity_priority - distribution_priority

        if priority > best_priority:
            best_priority = priority
            best_node = i

    return best_node
